@Injectable({
  providedIn: 'root'
})
export class TutorialService {
  private authService = inject(AuthService);
  private supabaseService = inject(SupabaseService);

  private _isVisible = signal(false);
  private _currentStep = signal(0);
  private _phase = signal<TutorialPhase>('modal');
  private _type = signal<TutorialType>('customer');
  private _showSkipConfirm = signal(false);
  private _refreshTrigger = signal(0);

  /** Esponiamo il segnale in sola lettura per i componenti che devono reagire */
  public refreshSignal = this._refreshTrigger.asReadonly();

  public isVisible = this._isVisible.asReadonly();
  public currentStep = this._currentStep.asReadonly();
  public phase = this._phase.asReadonly();
  public type = this._type.asReadonly();
  public showSkipConfirm = this._showSkipConfirm.asReadonly();

  // SUBSTEP
  private _currentSubStep = signal(0);
  public currentSubStep = this._currentSubStep.asReadonly();
  private _isIntroStep = signal(false);
  public isIntroStep = this._isIntroStep.asReadonly();

  // TUTORIAL SETTORIALE
  private _singleModeStepId: string | null = null;
  private _overviewMode = signal(false);
  public overviewMode = this._overviewMode.asReadonly();
  public static readonly BUSINESS_STEPS = BUSINESS_STEPS;
  public static readonly CUSTOMER_STEPS = CUSTOMER_STEPS;

  public steps = computed<TutorialStep[]>(() => {
    const allSteps = this._type() === 'business' ? BUSINESS_STEPS : CUSTOMER_STEPS;
    return this._getVisibleSteps(allSteps);
  });

  public refreshTooltip(): void {
    this._refreshTrigger.update(v => v + 1);
  }

  public currentStepData = computed<TutorialStep | null>(() => {
    const steps = this.steps();
    const idx = this._currentStep();
    return steps[idx] ?? null;
  });

  public isLastStep = computed(() =>
    this._currentStep() === this.steps().length - 1
  );

  public progress = computed(() =>
    Math.round(((this._currentStep() + 1) / this.steps().length) * 100)
  );

  // ------------------------------------------------------------------
  // Punto di ingresso: chiamato al login E ad ogni context switch
  // ------------------------------------------------------------------
  public async checkAndStart(): Promise<void> {
    if (this._isVisible()) return;

    const user = this.authService.currentUserValue;
    if (!user) return;

    const context = this.authService.getCurrentContext();
    const tutorialType: TutorialType = context === 'staff' ? 'business' : 'customer';
    const flagKey = tutorialType === 'business'
      ? 'tutorial_business_completed'
      : 'tutorial_customer_completed';

    try {
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('users')
        .select(flagKey)
        .eq('id', user.id)
        .single();

      if (error) throw error;
      if ((data as any)?.[flagKey] === true) return;

    } catch (e) {
      console.warn('[Tutorial] Impossibile leggere il flag, uso cache locale');
      if ((user as any)[flagKey] === true) return;
    }

    this._type.set(tutorialType);
    this._currentStep.set(0);
    this._phase.set('modal');
    this._showSkipConfirm.set(false);
    this._singleModeStepId = null; 
    this._overviewMode.set(true);
    this._isVisible.set(true);
  }

  // ------------------------------------------------------------------
  // Navigazione step
  // ------------------------------------------------------------------
public nextStep(): void {
  if (this._phase() === 'modal') {
    if (this._overviewMode()) {
      // Fase panoramica: avanza semplicemente allo step successivo
      if (this.isLastStep()) {
        // Fine della panoramica: passa alla fase tooltip
        this._overviewMode.set(false);
        this._phase.set('tooltip');
        this._currentStep.set(0);
        // Imposta l'intro per il primo step se ha sottostep
        const firstStep = this.steps()[0];
        this._isIntroStep.set(firstStep?.subSteps?.length ? true : false);
        this._currentSubStep.set(0);
      } else {
        this._currentStep.update(s => s + 1);
      }
    } else {
      // Non dovrebbe accadere (tutorial settoriale parte in tooltip), ma teniamo per sicurezza
      const step = this.currentStepData();
      const hasSubSteps = (step?.subSteps?.length ?? 0) > 0;
      if (hasSubSteps) {
        this._phase.set('tooltip');
        this._isIntroStep.set(true);
        this._currentSubStep.set(0);
      } else {
        if (this._singleModeStepId !== null) {
          this.completeTutorial();
        } else if (this.isLastStep()) {
          this.completeTutorial();
        } else {
          this._currentStep.update(s => s + 1);
        }
      }
    }
    return;
  }

  if (this._phase() === 'tooltip') {
    if (this._isIntroStep()) {
      this._isIntroStep.set(false);
      return;
    }

    if (!this.isLastSubStep()) {
      this._currentSubStep.update(s => s + 1);
      return;
    }

    // Fine dei sottostep dello step corrente
    if (this._singleModeStepId !== null) {
      this.completeTutorial();
    } else if (this.isLastStep()) {
      this.completeTutorial();
    } else {
      // Passa allo step successivo, sempre in fase tooltip
      this._currentStep.update(s => s + 1);
      const nextStep = this.steps()[this._currentStep()];
      this._isIntroStep.set(nextStep?.subSteps?.length ? true : false);
      this._currentSubStep.set(0);
      // La fase rimane 'tooltip'
    }
  }
}

public prevStep(): void {
  if (this._phase() === 'modal') {
    if (this._overviewMode()) {
      if (this._currentStep() > 0) {
        this._currentStep.update(s => s - 1);
      }
    } else {
      // Non usato, ma per completezza si potrebbe gestire
    }
    return;
  }

  if (this._phase() === 'tooltip') {
    if (this._isIntroStep()) {
      // Dall'intro si torna allo step precedente (in tooltip)
      if (this._currentStep() > 0) {
        this._currentStep.update(s => s - 1);
        const prevStep = this.steps()[this._currentStep()];
        if (prevStep?.subSteps?.length) {
          this._isIntroStep.set(true);
          this._currentSubStep.set(0);
        } else {
          this._isIntroStep.set(false);
          this._currentSubStep.set(0);
        }
      }
      return;
    }

    if (this._currentSubStep() > 0) {
      this._currentSubStep.update(s => s - 1);
      return;
    }

    // Se siamo al primo sottostep, andiamo all'intro dello stesso step
    const step = this.currentStepData();
    if (step?.subSteps?.length) {
      this._isIntroStep.set(true);
      return;
    }

    // Altrimenti, torna allo step precedente
    if (this._currentStep() > 0) {
      this._currentStep.update(s => s - 1);
      const prevStep = this.steps()[this._currentStep()];
      if (prevStep?.subSteps?.length) {
        this._isIntroStep.set(false);
        this._currentSubStep.set(prevStep.subSteps.length - 1);
      } else {
        this._isIntroStep.set(false);
        this._currentSubStep.set(0);
      }
    }
  }
}


  // ------------------------------------------------------------------
  // Skip
  // ------------------------------------------------------------------
  public requestSkip(): void { this._showSkipConfirm.set(true); }
  public cancelSkip(): void { this._showSkipConfirm.set(false); }
  public confirmSkip(): void {
    this._showSkipConfirm.set(false);
    this.completeTutorial();
  }

  // ------------------------------------------------------------------
  // Completamento
  // ------------------------------------------------------------------
  public async completeTutorial(): Promise<void> {
    this._isVisible.set(false);
    this._phase.set('done');
    await this.saveCompletionFlag();
  }

  private async saveCompletionFlag(): Promise<void> {
    const user = this.authService.currentUserValue;
    if (!user) return;

    const flagKey = this._type() === 'business'
      ? 'tutorial_business_completed'
      : 'tutorial_customer_completed';

    try {
      const { error } = await this.supabaseService.getSupabaseClient()
        .from('users')
        .update({ [flagKey]: true })
        .eq('id', user.id);

      if (!error) {
        (user as any)[flagKey] = true;
      } else {
        console.error('❌ Errore salvataggio tutorial flag:', error);
      }
    } catch (e) {
      console.error('❌ Eccezione salvataggio tutorial flag:', e);
    }
  }

  public restartTutorial(type: TutorialType): void {
    this._type.set(type);
    this._currentStep.set(0);
    this._phase.set('modal');
    this._showSkipConfirm.set(false);
    this._singleModeStepId = null;
    this._overviewMode.set(true);
    this._isVisible.set(true);
  }

  // Metodo che restituisce solo gli step accessibili all'utente corrente
  private _getVisibleSteps(steps: TutorialStep[]): TutorialStep[] {
    return steps.filter(step => {
      // Step senza permesso richiesto: sempre visibile (es. welcome)
      if (!step.requiredPermission) return true;
      // Filtra in base ai permessi dell'utente
      return this.authService.hasPermission(step.requiredPermission);
    });
  }

  // Computed: restituisce i dati effettivi del tooltip (sub-step se presente, altrimenti step principale)
public currentTooltipData = computed(() => {
  const step = this.currentStepData();
  if (!step) return null;

  // Se siamo nell'intro della madre
  if (this._isIntroStep()) {
    return {
      // Usa il tooltipTarget dello step principale se esiste
      tooltipTarget: step.tooltipTarget,
      tooltipPosition: step.tooltipPosition,
      title: step.title,
      description: step.description
    };
  }

  if (step.subSteps && step.subSteps.length > 0) {
    return step.subSteps[this._currentSubStep()] ?? null;
  }

  return {
    tooltipTarget: step.tooltipTarget,
    tooltipPosition: step.tooltipPosition,
    title: step.title,
    description: step.description
  };
});


public hasSubSteps = computed(() => {
  const step = this.currentStepData();
  return (step?.subSteps?.length ?? 0) > 0;
});

public isLastSubStep = computed(() => {
  const step = this.currentStepData();
  if (!step?.subSteps?.length) return true;
  return this._currentSubStep() === step.subSteps.length - 1;
});

public subStepProgress = computed(() => {
  const step = this.currentStepData();
  if (!step?.subSteps?.length) return null;
  return { current: this._currentSubStep() + 1, total: step.subSteps.length };
});

/**
 * Avvia il tutorial a partire da uno step specifico (per ID)
 * @param stepId L'ID dello step da cui iniziare
 * @param mode 'fromHere' (default) parte dallo step e continua fino alla fine;
 *             'single' mostra solo quello step (con i suoi sottostep) e poi termina.
 */


public startTutorialFromStep(stepId: string, mode: 'fromHere' | 'single' = 'fromHere'): void {
  // 1. Determina il tipo in base al contesto corrente
  const context = this.authService.getCurrentContext();
  const tutorialType: TutorialType = context === 'staff' ? 'business' : 'customer';
  
  // 2. Sceglie l'array corretto
  const allSteps = tutorialType === 'business' ? BUSINESS_STEPS : CUSTOMER_STEPS;
  
  // 3. Filtra per permessi (come _getVisibleSteps)
  const visibleSteps = allSteps.filter(step => {
    if (!step.requiredPermission) return true;
    return this.authService.hasPermission(step.requiredPermission);
  });

  // 4. Trova l'indice dello step richiesto
  const index = visibleSteps.findIndex(s => s.id === stepId);
  if (index === -1) return;

  // 5. Nasconde il tutorial se già visibile
  if (this._isVisible()) {
    this._isVisible.set(false);
  }

  // 6. Imposta lo stato interno
  this._type.set(tutorialType);
  this._currentStep.set(index);
  this._phase.set('tooltip');
  
  const step = visibleSteps[index];
  if (step.subSteps && step.subSteps.length > 0) {
    // ✅ MODIFICA: parti dall'intro invece che dal primo substep
    this._isIntroStep.set(true);
    this._currentSubStep.set(0);
  } else {
    this._isIntroStep.set(false);
    this._currentSubStep.set(0);
  }
  
  this._showSkipConfirm.set(false);
  this._singleModeStepId = mode === 'single' ? stepId : null;
  this._overviewMode.set(false);
  this._isVisible.set(true);
}

}